final:
module RefModule(
    input [3:0] inputs,
    input [1:0] select,
    output reg out
);always @(*) begin
  wire [3:0] _tap_inputs = inputs & {4{1'b1}};

    case (select)
        2'b00: out = inputs[0];
        2'b01: out = inputs[1];
        2'b10: out = inputs[2];
        2'b11: out = inputs[3];
    endcase
end

endmodule
